<?php require_once 'db.php'; $u=require_login('admin'); $stats=['students'=>pdo()->query("SELECT COUNT(*) FROM users u JOIN roles r ON r.id=u.role_id WHERE r.name='student'")->fetchColumn(),'librarians'=>pdo()->query("SELECT COUNT(*) FROM users u JOIN roles r ON r.id=u.role_id WHERE r.name='librarian'")->fetchColumn(),'tables'=>pdo()->query('SELECT COUNT(*) FROM library_tables')->fetchColumn(),'revenue'=>pdo()->query("SELECT COALESCE(SUM(amount),0) FROM payments WHERE status='verified'")->fetchColumn()]; $users=pdo()->query('SELECT u.id,u.name,u.email,r.name role,u.status FROM users u JOIN roles r ON r.id=u.role_id ORDER BY u.id DESC LIMIT 50')->fetchAll(); $bookings=pdo()->query('SELECT b.*,u.name,t.table_code FROM bookings b JOIN users u ON u.id=b.student_id JOIN library_tables t ON t.id=b.table_id ORDER BY b.created_at DESC LIMIT 50')->fetchAll(); app_header('Admin Dashboard'); ?><h1>Admin Dashboard</h1><section class="grid4"><?php foreach($stats as $k=>$v):?><div class="card stat"><b><?=e(ucfirst($k))?></b><span><?=e($v)?></span></div><?php endforeach;?></section><section class="card"><h2>Manage Users</h2><table><tr><th>ID</th><th>Name</th><th>Email</th><th>Role</th><th>Status</th></tr><?php foreach($users as $r):?><tr><td><?=e($r['id'])?></td><td><?=e($r['name'])?></td><td><?=e($r['email'])?></td><td><?=e($r['role'])?></td><td><?=e($r['status'])?></td></tr><?php endforeach;?></table></section><section class="card"><h2>Bookings & Reports</h2><table><tr><th>Student</th><th>Table</th><th>Status</th><th>Amount</th><th>Dates</th></tr><?php foreach($bookings as $b):?><tr><td><?=e($b['name'])?></td><td><?=e($b['table_code'])?></td><td><?=e($b['status'])?></td><td>₹<?=e($b['amount'])?></td><td><?=e($b['start_date'])?> - <?=e($b['expiry_date'])?></td></tr><?php endforeach;?></table></section><?php app_footer(); ?>
